"""
MABE Bootstrap: Inorganic Surface Adapter (Anti-Carbon-Bias)

Run: python3 bootstrap_inorganic_surfaces.py

Creates 2 files:
  core/inorganic_surfaces.py       — 18 surface materials, binding prediction
  tests/test_inorganic_surfaces.py — 33 tests

Materials: SiO2 (native + 4 grafted), MCM-41, SBA-15,
  Fe2O3, Fe3O4, FeOOH, Al2O3, TiO2, hydroxyapatite,
  montmorillonite, kaolinite, zeolite NaA/NaX, clinoptilolite

API:
  predict_surface_binding("Pb2+", "hydroxyapatite", pH=6.0)
  recommend_surface("Hg2+", require_magnetic=True)
  compare_surfaces_for_target("Cs+", competitors=["Na+"])

33 tests, 0 failed
"""
import base64, pathlib

FILES = {
    "core/inorganic_surfaces.py": "",
    "tests/test_inorganic_surfaces.py": "",
}

def main():
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(base64.b64decode(b64))
        print(f"  Wrote {path} ({len(base64.b64decode(b64)):,} bytes)")
    print()
    print("  python3 -m pytest tests/test_inorganic_surfaces.py -v")

if __name__ == "__main__":
    main()